const cotType = env.get('COT_TYPE') || 'a-u-G';
const uidPrefix = env.get('UID_PREFIX') || 'geojson';
const staleSec = parseInt(env.get('STALE_SECONDS') || '300', 10);
const callsignProp = env.get('CALLSIGN_PROP') || 'name';
const remarksProp = env.get('REMARKS_PROP') || 'description';
const altitudeProp = env.get('ALTITUDE_PROP') || '';
const speedProp = env.get('SPEED_PROP') || '';
const courseProp = env.get('COURSE_PROP') || '';

function xmlEsc(s) {
    return String(s == null ? '' : s).replace(/[<>&"']/g, c => ({
        '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&apos;'
    }[c]));
}

function num(v, fallback) {
    const n = Number(v);
    return Number.isFinite(n) ? n : fallback;
}

function iso(ms) { return new Date(ms).toISOString(); }

function stableUid(feature, idx) {
    const id = feature.id != null ? feature.id
             : feature.properties && feature.properties.id != null ? feature.properties.id
             : idx;
    return `${uidPrefix}-${id}`;
}

function featuresOf(payload) {
    if (!payload) return [];
    if (payload.type === 'Feature') return [payload];
    if (payload.type === 'FeatureCollection') return payload.features || [];
    if (Array.isArray(payload)) return payload;
    return [];
}

function trackElement(props) {
    if (!speedProp && !courseProp) return '';
    const hasSpeed = speedProp && props[speedProp] != null && Number.isFinite(Number(props[speedProp]));
    const hasCourse = courseProp && props[courseProp] != null && Number.isFinite(Number(props[courseProp]));
    if (!hasSpeed && !hasCourse) return '';
    const course = hasCourse ? Number(props[courseProp]) : 0;
    const speed = hasSpeed ? Number(props[speedProp]) : 0;
    return `<track course="${course}" speed="${speed}"/>`;
}

function pointCot(feature, idx, now, stale) {
    const coords = feature.geometry.coordinates;
    const lon = num(coords[0], null);
    const lat = num(coords[1], null);
    if (lat == null || lon == null) return null;
    const coordHae = num(coords[2], 0);
    const props = feature.properties || {};
    const hae = altitudeProp ? num(props[altitudeProp], coordHae) : coordHae;
    const callsign = props[callsignProp] || '';
    const remarks = props[remarksProp] || '';
    const uid = stableUid(feature, idx);
    return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<event version="2.0" uid="${xmlEsc(uid)}" type="${xmlEsc(cotType)}" how="m-g" time="${now}" start="${now}" stale="${stale}"><point lat="${lat}" lon="${lon}" hae="${hae}" ce="9999999.0" le="9999999.0"/><detail><contact callsign="${xmlEsc(callsign)}"/>${trackElement(props)}<remarks>${xmlEsc(remarks)}</remarks></detail></event>`;
}

function shapeCot(feature, idx, now, stale, vertices) {
    // GeoJSON polygon rings are closed — first and last vertex are identical.
    // Drop the duplicate before averaging so the centroid isn't biased.
    const n = vertices.length;
    const first = vertices[0], last = vertices[n - 1];
    const closed = n > 1 && first[0] === last[0] && first[1] === last[1];
    const ring = closed ? vertices.slice(0, -1) : vertices;
    let sumLat = 0, sumLon = 0;
    let links = '';
    for (const v of vertices) {
        const vLon = num(v[0], 0);
        const vLat = num(v[1], 0);
        const vHae = num(v[2], 0);
        links += `<link point="${vLat},${vLon},${vHae}"/>`;
    }
    for (const v of ring) {
        sumLat += num(v[1], 0);
        sumLon += num(v[0], 0);
    }
    const cLat = sumLat / ring.length;
    const cLon = sumLon / ring.length;
    const props = feature.properties || {};
    const callsign = props[callsignProp] || '';
    const remarks = props[remarksProp] || '';
    const uid = stableUid(feature, idx);
    const shapeType = cotType.startsWith('u-d') ? cotType : 'u-d-f';
    return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>\n<event version="2.0" uid="${xmlEsc(uid)}" type="${xmlEsc(shapeType)}" how="m-g" time="${now}" start="${now}" stale="${stale}"><point lat="${cLat}" lon="${cLon}" hae="0" ce="9999999.0" le="9999999.0"/><detail>${links}<strokeColor value="-65536"/><strokeWeight value="2.0"/><fillColor value="1073741824"/><labels_on value="true"/><contact callsign="${xmlEsc(callsign)}"/><remarks>${xmlEsc(remarks)}</remarks></detail></event>`;
}

function buildCot(feature, idx, now, stale) {
    const geom = feature && feature.geometry;
    if (!geom) return null;
    if (geom.type === 'Point') return pointCot(feature, idx, now, stale);
    if (geom.type === 'Polygon') {
        const ring = (geom.coordinates && geom.coordinates[0]) || [];
        if (ring.length < 3) return null;
        return shapeCot(feature, idx, now, stale, ring);
    }
    if (geom.type === 'LineString') {
        const line = geom.coordinates || [];
        if (line.length < 2) return null;
        return shapeCot(feature, idx, now, stale, line);
    }
    return null;
}

const features = featuresOf(msg.payload);
const now = iso(Date.now());
const stale = iso(Date.now() + staleSec * 1000);

const out = [];
for (let i = 0; i < features.length; i++) {
    const cot = buildCot(features[i], i, now, stale);
    if (cot == null) continue;
    out.push({ payload: cot, topic: stableUid(features[i], i) });
}

return [out];
